const command = msg.command || {};
const authUser = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
  ? JSON.parse(JSON.stringify(msg.payload))
  : null;
const stationid = String(command.stationid || command.kiosk?.stationid || '').trim();
const now = Date.now();
const volume = Number(command.volume);
const requestId = String(command.requestId || `set-volume-${stationid || 'unknown'}-${now}`).trim();

function response(status, statusEn, extra = {}) {
  return {
    _session: msg._session,
    payload: {
      action: 'set volume',
      stationid,
      kiosk: stationid,
      status,
      status_en: statusEn,
      requestId,
      timerequested: Number(command.timerequested || now),
      timeresponded: Date.now(),
      ...extra
    }
  };
}

if (!stationid) {
  return [null, response(0, 'Missing stationid for V2 audio command')];
}

if (!Number.isFinite(volume) || volume < 0 || volume > 100) {
  return [null, response(0, 'Volume must be between 0 and 100')];
}

msg._v2Audio = {
  authUser,
  command: { ...command, requestId, volume: Math.round(volume) },
  stationid,
  requestId,
  timerequested: Number(command.timerequested || now),
  volume: Math.round(volume)
};
msg.payload = {
  path: 'kiosks',
  query: [{ fieldPath: 'stationid', opStr: '==', value: stationid }]
};
return [msg, null];

const V2_TYPES = new Set(['CT3', 'CT4', 'CT8', 'CT12', 'CK48']);
const docs = Array.isArray(msg.payload) ? msg.payload : [];
const ctx = msg._v2Audio || {};
const command = ctx.command || msg.command || {};
const authUser = ctx.authUser || null;
const stationid = String(ctx.stationid || command.stationid || '').trim();
const volume = Number(ctx.volume);
const requestId = String(ctx.requestId || command.requestId || `set-volume-${stationid}-${Date.now()}`).trim();
const timerequested = Number(ctx.timerequested || command.timerequested || Date.now());
const sessionValue = msg._session || command.admin || null;

function buildResponse(status, statusEn, extra = {}) {
  return {
    _session: sessionValue,
    payload: {
      action: 'set volume',
      stationid,
      kiosk: stationid,
      status,
      status_en: statusEn,
      volume,
      muted: volume === 0,
      requestId,
      timerequested,
      timeresponded: Date.now(),
      ...extra
    }
  };
}

function toModules(kiosk) {
  if (Array.isArray(kiosk?.modules)) return kiosk.modules;
  if (kiosk?.modules && typeof kiosk.modules === 'object') return Object.values(kiosk.modules);
  return [];
}

function getModuleIds(kiosk) {
  const seen = new Set();
  return toModules(kiosk)
    .map((module) => String(module?.id || '').trim())
    .filter((moduleid) => {
      if (!moduleid || seen.has(moduleid)) return false;
      seen.add(moduleid);
      return true;
    });
}

if (!authUser) {
  return [null, buildResponse(0, 'V2 audio command requires authenticated dashboard context'), null];
}

const isAdmin = authUser.role === 'admin' || authUser.username === 'chargerent';
if (!isAdmin && authUser.commands?.audio !== true) {
  return [null, buildResponse(0, 'Permission denied'), null];
}

if (docs.length === 0) {
  return [null, buildResponse(0, `Kiosk ${stationid} not found`), null];
}

const kiosk = docs[0] || {};
const hardwareType = String(kiosk?.hardware?.type || '').toUpperCase();
const modules = toModules(kiosk);
const moduleids = getModuleIds(kiosk);
const isV2 = kiosk?.isNewSchema === true || V2_TYPES.has(hardwareType) || modules.some((module) => Array.isArray(module?.slots));
if (!isV2) {
  return [null, buildResponse(0, `${stationid} is not a V2 kiosk`), null];
}

if (!Number.isFinite(volume) || volume < 0 || volume > 100) {
  return [null, buildResponse(0, 'Volume must be between 0 and 100'), null];
}

if (moduleids.length === 0) {
  return [null, buildResponse(0, `No modules found for ${stationid}`), null];
}

const roundedVolume = Math.round(volume);
const publishMessages = moduleids.map((moduleid) => ({
  topic: `/${stationid}/${moduleid}/user/get`,
  payload: {
    cmd: 'volume',
    data: String(roundedVolume)
  },
  qos: '0',
  retain: 'false'
}));

const responseMessage = buildResponse(
  1,
  `Volume set to ${roundedVolume}% on ${stationid} (${moduleids.length} modules)`,
  { moduleids, moduleCount: moduleids.length }
);
const provisionid = String(kiosk?.provisionid || '').trim();
const firestoreMessage = provisionid
  ? {
      payload: {
        path: `kiosks/${provisionid}`,
        content: {
          hardware: {
            ...(kiosk.hardware || {}),
            volume: roundedVolume,
            audio: roundedVolume === 0 ? 'off' : 'on'
          },
          updatedAt: new Date().toISOString()
        }
      }
    }
  : null;

node.warn(`Dashboard set volume ${roundedVolume} for ${stationid} modules [${moduleids.join(', ')}] request ${requestId}`);
return [publishMessages, responseMessage, firestoreMessage];
